from itertools import permutations

class Solution:
    def tupleSameProduct(self, nums):
        n = len(nums)
        count = 0
        for a, b, c, d in permutations(range(n), 4):
            if nums[a] * nums[b] == nums[c] * nums[d]:
                count += 1
        return count

