from collections import defaultdict

class Solution:
    def tupleSameProduct(self, nums):
        counts = defaultdict(int)
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                counts[nums[i] * nums[j]] += 1
        total = 0
        for c in counts.values():
            total += c * (c - 1) // 2
        return total * 8

