var tupleSameProduct = function(nums) {
    const counts = new Map();
    const n = nums.length;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const p = nums[i] * nums[j];
            counts.set(p, (counts.get(p) || 0) + 1);
        }
    }
    let total = 0;
    for (const c of counts.values()) {
        total += (c * (c - 1)) / 2;
    }
    return total * 8;
};
